package com.evolua.auth.infrastructure.security; import io.jsonwebtoken.Claims; import io.jsonwebtoken.Jwts; import io.jsonwebtoken.security.Keys; import java.nio.charset.StandardCharsets; import java.util.List; import javax.crypto.SecretKey; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Component; @Component public class JwtService { private final SecretKey key; public JwtService(@Value("${app.security.jwt.secret}") String secret) { this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8)); } public AuthenticatedUser parse(String token) { Claims claims = Jwts.parser().verifyWith(key).build().parseSignedClaims(token).getPayload(); List<String> roles = claims.get("roles", List.class); return new AuthenticatedUser(claims.getSubject(), claims.get("email", String.class), roles == null ? List.of() : roles); } }
